1	package com.dispatchops.infrastructure.security;
2	
3	import javax.crypto.Cipher;
4	import javax.crypto.spec.IvParameterSpec;
5	import javax.crypto.spec.SecretKeySpec;
6	import java.nio.charset.StandardCharsets;
7	import java.security.SecureRandom;
8	
9	public final class AesUtil {
10	
11	    private static final String ALGORITHM = "AES/CBC/PKCS5Padding";
12	    private static final int IV_LENGTH = 16;
13	
14	    private AesUtil() {
15	    }
16	
17	    public static byte[] encrypt(byte[] plaintext, String hexKey) {
18	        try {
19	            byte[] keyBytes = hexToBytes(hexKey);
20	            SecretKeySpec secretKey = new SecretKeySpec(keyBytes, "AES");
21	
22	            byte[] iv = new byte[IV_LENGTH];
23	            new SecureRandom().nextBytes(iv);
24	            IvParameterSpec ivSpec = new IvParameterSpec(iv);
25	
26	            Cipher cipher = Cipher.getInstance(ALGORITHM);
27	            cipher.init(Cipher.ENCRYPT_MODE, secretKey, ivSpec);
28	            byte[] encrypted = cipher.doFinal(plaintext);
29	
30	            byte[] result = new byte[IV_LENGTH + encrypted.length];
31	            System.arraycopy(iv, 0, result, 0, IV_LENGTH);
32	            System.arraycopy(encrypted, 0, result, IV_LENGTH, encrypted.length);
33	            return result;
34	        } catch (Exception e) {
35	            throw new RuntimeException("AES encryption failed", e);
36	        }
37	    }
38	
39	    public static byte[] decrypt(byte[] ciphertext, String hexKey) {
40	        try {
41	            byte[] keyBytes = hexToBytes(hexKey);
42	            SecretKeySpec secretKey = new SecretKeySpec(keyBytes, "AES");
43	
44	            byte[] iv = new byte[IV_LENGTH];
45	            System.arraycopy(ciphertext, 0, iv, 0, IV_LENGTH);
46	            IvParameterSpec ivSpec = new IvParameterSpec(iv);
47	
48	            byte[] encryptedData = new byte[ciphertext.length - IV_LENGTH];
49	            System.arraycopy(ciphertext, IV_LENGTH, encryptedData, 0, encryptedData.length);
50	
51	            Cipher cipher = Cipher.getInstance(ALGORITHM);
52	            cipher.init(Cipher.DECRYPT_MODE, secretKey, ivSpec);
53	            return cipher.doFinal(encryptedData);
54	        } catch (Exception e) {
55	            throw new RuntimeException("AES decryption failed", e);
56	        }
57	    }
58	
59	    public static byte[] encryptString(String plaintext, String hexKey) {
60	        if (plaintext == null) return null;
61	        return encrypt(plaintext.getBytes(StandardCharsets.UTF_8), hexKey);
62	    }
63	
64	    public static String decryptString(byte[] ciphertext, String hexKey) {
65	        if (ciphertext == null) return null;
66	        byte[] decrypted = decrypt(ciphertext, hexKey);
67	        return new String(decrypted, StandardCharsets.UTF_8);
68	    }
69	
70	    public static byte[] hexToBytes(String hex) {
71	        int len = hex.length();
72	        byte[] data = new byte[len / 2];
73	        for (int i = 0; i < len; i += 2) {
74	            data[i / 2] = (byte) ((Character.digit(hex.charAt(i), 16) << 4)
75	                    + Character.digit(hex.charAt(i + 1), 16));
76	        }
77	        return data;
78	    }
79	}
