6	@Component
7	public class FieldEncryptionService {
8	
9	    private final String aesKey;
10	
11	    public FieldEncryptionService(@Value("${security.aes.key}") String aesKey) {
12	        this.aesKey = aesKey;
13	    }
14	
15	    public byte[] encrypt(String plaintext) {
16	        if (plaintext == null) {
17	            return null;
18	        }
19	        return AesUtil.encryptString(plaintext, aesKey);
20	    }
21	
22	    public String decrypt(byte[] ciphertext) {
23	        if (ciphertext == null) {
24	            return null;
25	        }
26	        return AesUtil.decryptString(ciphertext, aesKey);
27	    }
28	}
