35	@Service
36	@Transactional
37	public class PaymentService {
38	
39	    private static final Logger log = LoggerFactory.getLogger(PaymentService.class);
40	    private static final long REFUND_ELIGIBLE_DAYS = 30;
41	    private static final String SYSTEM_ACCOUNT_USERNAME = "system";
42	
43	    /** Resolved at startup from DB by username='system' */
44	    private Long systemAccountId;
45	
46	    private final PaymentMapper paymentMapper;
47	    private final LedgerEntryMapper ledgerEntryMapper;
48	    private final ReconciliationItemMapper reconciliationItemMapper;
49	    private final DeviceCredentialMapper deviceCredentialMapper;
