55	    public PaymentService(PaymentMapper paymentMapper,
56	                          LedgerEntryMapper ledgerEntryMapper,
57	                          ReconciliationItemMapper reconciliationItemMapper,
58	                          DeviceCredentialMapper deviceCredentialMapper,
59	                          CallbackEventMapper callbackEventMapper,
60	                          NotificationService notificationService,
61	                          SearchService searchService,
62	                          com.dispatchops.infrastructure.persistence.mapper.UserMapper userMapper,
63	                          @Value("${security.hmac.key}") String hmacKey) {
64	        this.paymentMapper = paymentMapper;
65	        this.ledgerEntryMapper = ledgerEntryMapper;
