84	    public Payment processPayment(PaymentCreateDTO dto, Long actorId) {
85	        log.info("Processing payment for jobId={} with idempotencyKey={}", dto.getJobId(), dto.getIdempotencyKey());
86	
87	        Payment existing = paymentMapper.findByIdempotencyKey(dto.getIdempotencyKey());
88	        if (existing != null) {
89	            if (existing.getStatus() == PaymentStatus.SETTLED
90	                    || existing.getStatus() == PaymentStatus.PENDING_SETTLEMENT) {
91	                log.info("Idempotent return for existing payment id={} with status={}",
92	                        existing.getId(), existing.getStatus());
93	                return existing;
94	            }
95	            if (existing.getStatus() != PaymentStatus.CANCELLED) {
96	                log.info("Existing payment id={} has status={}, returning as-is",
97	                        existing.getId(), existing.getStatus());
98	                return existing;
99	            }
100	            log.info("Previous payment id={} was CANCELLED, allowing retry", existing.getId());
101	        }
102	
103	        PaymentMethod method = PaymentMethod.valueOf(dto.getMethod());
104	
105	        // For INTERNAL_BALANCE: check available funds before proceeding
106	        if (method == PaymentMethod.INTERNAL_BALANCE) {
107	            BigDecimal available = ledgerEntryMapper.calculateBalance(actorId);
108	            if (available == null) available = BigDecimal.ZERO;
109	            if (available.compareTo(dto.getAmount()) < 0) {
110	                throw new com.dispatchops.domain.exception.InsufficientFundsException(
111	                        "Insufficient internal balance. Available: $" + available + ", Requested: $" + dto.getAmount(),
112	                        available, dto.getAmount());
113	            }
114	        }
115	
116	        Payment payment = new Payment();
117	        payment.setIdempotencyKey(dto.getIdempotencyKey());
118	        payment.setJobId(dto.getJobId());
119	        payment.setPayerId(actorId);
120	        payment.setAmount(dto.getAmount());
121	        payment.setMethod(method);
122	        payment.setStatus(PaymentStatus.PENDING_SETTLEMENT);
123	        payment.setCheckNumber(dto.getCheckNumber());
124	        payment.setDeviceId(dto.getDeviceId());
125	        payment.setDeviceSeqId(dto.getDeviceSeqId());
126	        payment.setCreatedAt(LocalDateTime.now());
127	        payment.setUpdatedAt(LocalDateTime.now());
128	
129	        try {
130	            paymentMapper.insert(payment);
131	        } catch (org.springframework.dao.DuplicateKeyException e) {
132	            // Concurrent insert with same idempotency_key — return existing payment
133	            log.info("Concurrent idempotency collision for key={}, returning existing", dto.getIdempotencyKey());
134	            Payment concurrent = paymentMapper.findByIdempotencyKey(dto.getIdempotencyKey());
135	            if (concurrent != null) {
136	                return concurrent;
137	            }
138	            throw e; // Should not happen, but re-throw if lookup fails
139	        }
140	        log.info("Payment id={} created with status PENDING_SETTLEMENT", payment.getId());
141	
142	        // Ledger entries are posted at SETTLEMENT, not at creation.
143	        // For INTERNAL_BALANCE: payer debit is reserved at settlement to maintain atomicity.
144	        // This keeps PENDING_SETTLEMENT as a pure "intent" state with no ledger impact,
145	        // so cancellation requires no compensating entries.
146	        log.debug("Payment id={} created in PENDING_SETTLEMENT — ledger entries deferred to settlement", payment.getId());
147	
148	        notificationService.notify(
149	                actorId,
150	                NotificationType.PAYMENT_EVENT,
151	                "Payment Processed",
152	                "Your payment of $" + dto.getAmount() + " has been submitted for settlement.",
153	                "Payment",
154	                payment.getId());
155	
156	        try { searchService.indexEntity("PAYMENT", payment.getId(), payment.getIdempotencyKey(),
157	                "Job " + payment.getJobId() + " " + payment.getMethod() + " " + payment.getAmount(),
158	                payment.getStatus().name(), payment.getPayerId()); }
159	        catch (Exception e) { log.warn("Failed to index payment: {}", e.getMessage()); }
160	
161	        return payment;
162	    }
163	
164	    public Payment settlePayment(Long paymentId, Long auditorId) {
165	        log.info("Settling payment id={} by auditorId={}", paymentId, auditorId);
166	
167	        Payment payment = paymentMapper.findById(paymentId);
168	        if (payment == null) {
169	            throw new ResourceNotFoundException("Payment not found with id: " + paymentId, "Payment", paymentId);
170	        }
171	
172	        if (payment.getStatus() != PaymentStatus.PENDING_SETTLEMENT) {
173	            throw new IllegalStateException(
174	                    "Cannot settle payment in status " + payment.getStatus() + ". Must be PENDING_SETTLEMENT.");
175	        }
176	
177	        StatusTransitionValidator.validatePaymentTransition(payment.getStatus(), PaymentStatus.SETTLED);
178	
179	        LocalDateTime now = LocalDateTime.now();
180	        LocalDateTime refundEligibleUntil = now.plusDays(REFUND_ELIGIBLE_DAYS);
181	
182	        int settled = paymentMapper.settle(paymentId, auditorId, now, refundEligibleUntil);
183	        if (settled == 0) {
184	            throw new IllegalStateException(
185	                    "Payment " + paymentId + " is no longer in PENDING_SETTLEMENT status (concurrent modification)");
186	        }
187	        payment.setStatus(PaymentStatus.SETTLED);
188	        payment.setSettledBy(auditorId);
189	        payment.setSettledAt(now);
190	        payment.setRefundEligibleUntil(refundEligibleUntil);
191	
192	        // For INTERNAL_BALANCE: debit payer account at settlement
193	        if (payment.getMethod() == PaymentMethod.INTERNAL_BALANCE) {
194	            BigDecimal payerBalance = ledgerEntryMapper.calculateBalance(payment.getPayerId());
195	            BigDecimal payerAfter = (payerBalance != null ? payerBalance : BigDecimal.ZERO)
196	                    .subtract(payment.getAmount());
197	
198	            LedgerEntry debitEntry = new LedgerEntry();
199	            debitEntry.setPaymentId(paymentId);
200	            debitEntry.setAccountId(payment.getPayerId());
201	            debitEntry.setEntryType(LedgerEntryType.DEBIT);
202	            debitEntry.setAmount(payment.getAmount());
203	            debitEntry.setBalanceAfter(payerAfter);
204	            debitEntry.setDescription("Settlement debit for payment " + paymentId);
205	            debitEntry.setReferenceType("Payment");
206	            debitEntry.setReferenceId(paymentId);
207	            debitEntry.setCreatedAt(LocalDateTime.now());
208	            ledgerEntryMapper.insert(debitEntry);
209	            log.debug("DEBIT ledger entry created for payer at settlement, payment id={}", paymentId);
210	        }
211	
212	        // All methods: credit org account at settlement
213	        Long orgAccountId = systemAccountId;
214	        BigDecimal orgBalance = ledgerEntryMapper.calculateBalance(orgAccountId);
215	        BigDecimal orgBalanceAfter = (orgBalance != null ? orgBalance : BigDecimal.ZERO)
216	                .add(payment.getAmount());
217	
218	        LedgerEntry creditEntry = new LedgerEntry();
219	        creditEntry.setPaymentId(paymentId);
220	        creditEntry.setAccountId(orgAccountId);
221	        creditEntry.setEntryType(LedgerEntryType.CREDIT);
222	        creditEntry.setAmount(payment.getAmount());
223	        creditEntry.setBalanceAfter(orgBalanceAfter);
224	        creditEntry.setDescription("Settlement for payment " + paymentId);
225	        creditEntry.setReferenceType("Payment");
226	        creditEntry.setReferenceId(paymentId);
227	        creditEntry.setCreatedAt(LocalDateTime.now());
228	
229	        ledgerEntryMapper.insert(creditEntry);
230	
231	        log.info("Payment id={} settled by auditor {}", paymentId, auditorId);
232	        try { searchService.indexEntity("PAYMENT", payment.getId(), payment.getIdempotencyKey(),
233	                "Job " + payment.getJobId() + " " + payment.getMethod() + " SETTLED",
234	                "SETTLED", payment.getPayerId()); }
235	        catch (Exception e) { log.warn("Failed to reindex payment: {}", e.getMessage()); }
236	        return payment;
237	    }
238	
239	    public List<Payment> settleBatch(List<Long> paymentIds, Long auditorId) {
240	        log.info("Settling batch of {} payments by auditorId={}", paymentIds.size(), auditorId);
241	
242	        List<Payment> results = new ArrayList<>();
243	        for (Long paymentId : paymentIds) {
244	            try {
245	                Payment settled = settlePayment(paymentId, auditorId);
246	                results.add(settled);
247	            } catch (Exception e) {
248	                log.error("Failed to settle payment id={}: {}", paymentId, e.getMessage());
249	                Payment failed = paymentMapper.findById(paymentId);
250	                if (failed != null) {
251	                    results.add(failed);
252	                }
253	            }
254	        }
255	
256	        log.info("Batch settlement complete: {} of {} payments settled", results.size(), paymentIds.size());
257	        return results;
258	    }
