260	    public Payment processRefund(Long paymentId, BigDecimal amount, String reason, Long actorId) {
261	        log.info("Processing refund for paymentId={}, amount={}, by actorId={}", paymentId, amount, actorId);
262	
263	        Payment payment = paymentMapper.findById(paymentId);
264	        if (payment == null) {
265	            throw new ResourceNotFoundException("Payment not found with id: " + paymentId, "Payment", paymentId);
266	        }
267	
268	        if (payment.getStatus() != PaymentStatus.SETTLED) {
269	            throw new IllegalStateException(
270	                    "Cannot refund payment in status " + payment.getStatus() + ". Must be SETTLED.");
271	        }
272	
273	        if (payment.getRefundEligibleUntil() == null) {
274	            throw new RefundWindowClosedException(
275	                    "Refund window not established for this payment. Cannot process refund without eligibility date.");
276	        }
277	        if (payment.getRefundEligibleUntil().isBefore(LocalDateTime.now())) {
278	            throw new RefundWindowClosedException(
279	                    "Refund window has closed. Refund was eligible until " + payment.getRefundEligibleUntil());
280	        }
281	
282	        if (amount.compareTo(payment.getAmount()) > 0) {
283	            throw new IllegalArgumentException(
284	                    "Refund amount $" + amount + " exceeds original payment amount $" + payment.getAmount());
285	        }
286	
287	        StatusTransitionValidator.validatePaymentTransition(payment.getStatus(), PaymentStatus.REFUND_PENDING);
288	        paymentMapper.updateStatus(paymentId, PaymentStatus.REFUND_PENDING.name(), PaymentStatus.SETTLED.name());
289	
290	        StatusTransitionValidator.validatePaymentTransition(PaymentStatus.REFUND_PENDING, PaymentStatus.REFUNDED);
291	        paymentMapper.updateStatus(paymentId, PaymentStatus.REFUNDED.name(), PaymentStatus.REFUND_PENDING.name());
292	
293	        payment.setStatus(PaymentStatus.REFUNDED);
294	
295	        // CREDIT to payer (refund back to payer)
296	        BigDecimal payerBalance = ledgerEntryMapper.calculateBalance(payment.getPayerId());
297	        BigDecimal payerBalanceAfter = (payerBalance != null ? payerBalance : BigDecimal.ZERO).add(amount);
298	
299	        LedgerEntry creditToPayer = new LedgerEntry();
300	        creditToPayer.setPaymentId(paymentId);
301	        creditToPayer.setAccountId(payment.getPayerId());
302	        creditToPayer.setEntryType(LedgerEntryType.CREDIT);
303	        creditToPayer.setAmount(amount);
304	        creditToPayer.setBalanceAfter(payerBalanceAfter);
305	        creditToPayer.setDescription("Refund for payment " + paymentId + ": " + reason);
306	        creditToPayer.setReferenceType("Payment");
307	        creditToPayer.setReferenceId(paymentId);
308	        creditToPayer.setCreatedAt(LocalDateTime.now());
309	        ledgerEntryMapper.insert(creditToPayer);
310	
311	        // DEBIT from org account
312	        Long orgAccountId = systemAccountId;
313	        BigDecimal orgBalance = ledgerEntryMapper.calculateBalance(orgAccountId);
314	        BigDecimal orgBalanceAfter = (orgBalance != null ? orgBalance : BigDecimal.ZERO).subtract(amount);
315	
316	        LedgerEntry debitFromOrg = new LedgerEntry();
317	        debitFromOrg.setPaymentId(paymentId);
318	        debitFromOrg.setAccountId(orgAccountId);
319	        debitFromOrg.setEntryType(LedgerEntryType.DEBIT);
320	        debitFromOrg.setAmount(amount);
321	        debitFromOrg.setBalanceAfter(orgBalanceAfter);
322	        debitFromOrg.setDescription("Refund debit for payment " + paymentId + ": " + reason);
323	        debitFromOrg.setReferenceType("Payment");
324	        debitFromOrg.setReferenceId(paymentId);
325	        debitFromOrg.setCreatedAt(LocalDateTime.now());
326	        ledgerEntryMapper.insert(debitFromOrg);
327	
328	        notificationService.notify(
329	                payment.getPayerId(),
330	                NotificationType.PAYMENT_EVENT,
331	                "Refund Processed",
332	                "A refund of $" + amount + " has been processed for your payment. Reason: " + reason,
333	                "Payment",
334	                paymentId);
335	
336	        log.info("Refund of {} processed for payment id={}", amount, paymentId);
337	        try { searchService.indexEntity("PAYMENT", payment.getId(), payment.getIdempotencyKey(),
338	                "Job " + payment.getJobId() + " " + payment.getMethod() + " REFUNDED",
339	                "REFUNDED", payment.getPayerId()); }
340	        catch (Exception e) { log.warn("Failed to reindex payment after refund: {}", e.getMessage()); }
341	        return payment;
342	    }
