344	    /**
345	     * Verify device callback signature.
346	     * Canonical signed string: deviceId + "|" + eventId + "|" + timestamp + "|" + payload
347	     * This cryptographically binds all metadata fields to prevent replay with substituted eventId/timestamp.
348	     */
349	    @Transactional(readOnly = true)
350	    public boolean verifyDeviceCallback(String deviceId, String eventId, String timestamp, String payload, String signature) {
351	        log.debug("Verifying device callback for deviceId={}, eventId={}", deviceId, eventId);
352	
353	        DeviceCredential credential = deviceCredentialMapper.findByDeviceId(deviceId);
354	        if (credential == null) {
355	            log.warn("No device credential found for deviceId={}", deviceId);
356	            return false;
357	        }
358	
359	        // Canonical string binds all fields: prevents replay with different eventId or timestamp
360	        String canonical = deviceId + "|" + eventId + "|" + timestamp + "|" + payload;
361	        String computed = HmacUtil.computeHmac(canonical, credential.getSharedSecret());
362	        boolean valid = java.security.MessageDigest.isEqual(
363	                computed.getBytes(java.nio.charset.StandardCharsets.UTF_8),
364	                signature.getBytes(java.nio.charset.StandardCharsets.UTF_8));
365	
366	        log.debug("Device callback verification for deviceId={}: valid={}", deviceId, valid);
367	        return valid;
368	    }
369	
370	    /** Maximum allowed clock drift for callback timestamps (5 minutes). */
371	    private static final long CALLBACK_TIMESTAMP_DRIFT_SECONDS = 300;
372	
373	    /**
374	     * Full device callback ingestion pipeline: receive -> persist -> verify -> process.
375	     * Timestamp is mandatory. Signature covers canonical string: deviceId|eventId|timestamp|payload.
376	     */
377	    public java.util.Map<String, Object> processDeviceCallback(
378	            String deviceId, String eventId, String payload, String signature,
379	            String sourceIp, Long deviceSeqId, String timestamp) {
380	        log.info("Processing device callback: deviceId={}, eventId={}", deviceId, eventId);
381	
382	        java.util.Map<String, Object> result = new java.util.LinkedHashMap<>();
383	
384	        // Step 1: Timestamp is mandatory and must be fresh
385	        if (timestamp == null || timestamp.isBlank()) {
386	            result.put("status", "REJECTED");
387	            result.put("reasonCode", "TIMESTAMP_MISSING");
388	            result.put("message", "Missing required field: timestamp (ISO-8601)");
389	            result.put("eventId", eventId);
390	            return result;
391	        }
392	        try {
393	            java.time.Instant callbackTime = java.time.Instant.parse(timestamp);
394	            long driftSeconds = Math.abs(java.time.Duration.between(callbackTime, java.time.Instant.now()).getSeconds());
395	            if (driftSeconds > CALLBACK_TIMESTAMP_DRIFT_SECONDS) {
396	                log.warn("Callback timestamp too stale: drift={}s, eventId={}", driftSeconds, eventId);
397	                result.put("status", "REJECTED");
398	                result.put("reasonCode", "TIMESTAMP_STALE");
399	                result.put("message", "Callback timestamp outside acceptable window (" + CALLBACK_TIMESTAMP_DRIFT_SECONDS + "s)");
400	                result.put("eventId", eventId);
401	                return result;
402	            }
403	        } catch (java.time.format.DateTimeParseException e) {
404	            log.warn("Invalid callback timestamp format for eventId={}: {}", eventId, timestamp);
405	            result.put("status", "REJECTED");
406	            result.put("reasonCode", "TIMESTAMP_INVALID");
407	            result.put("message", "Invalid timestamp format. Use ISO-8601.");
408	            result.put("eventId", eventId);
409	            return result;
410	        }
411	
412	        // Step 2: Replay protection - check if eventId already exists (pre-check)
413	        com.dispatchops.domain.model.CallbackEvent existing = callbackEventMapper.findByEventId(eventId);
414	        if (existing != null) {
415	            log.info("Duplicate callback eventId={} (status={})", eventId, existing.getStatus());
416	            result.put("status", "DUPLICATE");
417	            result.put("message", "Callback already processed");
418	            result.put("eventId", eventId);
419	            result.put("originalStatus", existing.getStatus());
420	            return result;
421	        }
422	
423	        // Step 3: Persist raw event (receipt durability) with DB-level unique constraint
424	        String payloadHash = HmacUtil.computeHmac(payload, hmacKey);
425	        com.dispatchops.domain.model.CallbackEvent event = new com.dispatchops.domain.model.CallbackEvent();
426	        event.setEventId(eventId);
427	        event.setDeviceId(deviceId);
428	        event.setDeviceSeqId(deviceSeqId);
429	        event.setPayloadHash(payloadHash);
430	        event.setRawPayload(payload);
431	        event.setSignature(signature);
432	        event.setSourceIp(sourceIp);
433	        event.setStatus("RECEIVED");
434	        event.setReceivedAt(java.time.LocalDateTime.now());
435	
436	        try {
437	            callbackEventMapper.insert(event);
438	        } catch (org.springframework.dao.DuplicateKeyException e) {
439	            log.info("Concurrent duplicate callback eventId={}, returning idempotent response", eventId);
440	            result.put("status", "DUPLICATE");
441	            result.put("message", "Callback already processed (concurrent)");
442	            result.put("eventId", eventId);
443	            return result;
444	        }
445	        log.debug("Callback event persisted: id={}, eventId={}", event.getId(), eventId);
446	
447	        // Step 4: Verify HMAC signature over canonical string (binds deviceId+eventId+timestamp+payload)
448	        boolean valid = verifyDeviceCallback(deviceId, eventId, timestamp, payload, signature);
449	        if (!valid) {
450	            callbackEventMapper.updateStatus(event.getId(), "FAILED", null, null, "Invalid HMAC signature");
451	            log.warn("Callback signature verification failed for eventId={}", eventId);
452	            result.put("status", "REJECTED");
453	            result.put("reasonCode", "AUTH_SIGNATURE_INVALID");
454	            result.put("message", "Invalid callback signature");
455	            result.put("eventId", eventId);
456	            return result;
457	        }
458	        callbackEventMapper.updateStatus(event.getId(), "VERIFIED", java.time.LocalDateTime.now(), null, null);
459	
460	        // Step 5: Business processing - reconcile payment state based on callback payload
461	        String processingError = null;
462	        try {
463	            processCallbackBusinessLogic(deviceId, payload, deviceSeqId);
464	        } catch (Exception e) {
465	            processingError = e.getMessage();
466	            log.error("Callback business processing failed for eventId={}: {}", eventId, processingError);
467	        }
468	
469	        if (processingError != null) {
470	            callbackEventMapper.updateStatus(event.getId(), "FAILED", null, null, processingError);
471	            result.put("status", "PROCESSED_WITH_ERROR");
472	            result.put("message", "Callback verified but processing failed: " + processingError);
473	            result.put("eventId", eventId);
474	            return result;
475	        }
476	
477	        callbackEventMapper.updateStatus(event.getId(), "PROCESSED", null, java.time.LocalDateTime.now(), null);
478	        log.info("Callback processed successfully: eventId={}, deviceId={}", eventId, deviceId);
479	        result.put("status", "PROCESSED");
480	        result.put("message", "Callback verified and processed");
481	        result.put("eventId", eventId);
482	        result.put("deviceId", deviceId);
483	        return result;
484	    }
