486	    /**
487	     * Domain-side business processing for a verified device callback.
488	     * Parses the payload and drives payment state transitions.
489	     */
490	    private void processCallbackBusinessLogic(String deviceId, String payload, Long deviceSeqId) {
491	        // Parse payload for payment reference and action
492	        // Expected format: JSON with fields like paymentRef, action (CONFIRM/CANCEL), amount
493	        try {
494	            com.fasterxml.jackson.databind.ObjectMapper mapper = new com.fasterxml.jackson.databind.ObjectMapper();
495	            @SuppressWarnings("unchecked")
496	            java.util.Map<String, Object> data = mapper.readValue(payload, java.util.Map.class);
497	
498	            String paymentRef = (String) data.get("paymentRef");
499	            String action = (String) data.get("action");
500	
501	            if (paymentRef != null && action != null) {
502	                Payment payment = paymentMapper.findByIdempotencyKey(paymentRef);
503	                if (payment != null) {
504	                    if ("CONFIRM".equals(action) && payment.getStatus() == PaymentStatus.PENDING_SETTLEMENT) {
505	                        log.info("Device callback confirms payment ref={}", paymentRef);
506	                        // Device confirms receipt - no state change needed, payment stays PENDING_SETTLEMENT
507	                        // until auditor settles via daily drawer close
508	                    } else if ("CANCEL".equals(action) && payment.getStatus() == PaymentStatus.PENDING_SETTLEMENT) {
509	                        log.info("Device callback cancels payment ref={}", paymentRef);
510	                        paymentMapper.updateStatus(payment.getId(),
511	                                PaymentStatus.CANCELLED.name(), PaymentStatus.PENDING_SETTLEMENT.name());
512	                        try { searchService.indexEntity("PAYMENT", payment.getId(), payment.getIdempotencyKey(),
513	                                "Job " + payment.getJobId() + " " + payment.getMethod() + " CANCELLED",
514	                                "CANCELLED", payment.getPayerId()); }
515	                        catch (Exception e) { log.warn("Failed to reindex cancelled payment: {}", e.getMessage()); }
516	                    }
517	                } else {
518	                    log.debug("No payment found for ref={}, callback recorded for reconciliation", paymentRef);
519	                }
520	            } else {
521	                log.debug("Callback payload has no paymentRef/action, recorded as informational");
522	            }
523	        } catch (com.fasterxml.jackson.core.JsonProcessingException e) {
524	            log.debug("Callback payload is not JSON, recorded as raw event");
525	        }
526	    }
