542	    @Transactional(readOnly = true)
543	    public byte[] generateReconciliationExport(LocalDate from, LocalDate to) {
544	        log.info("Generating reconciliation export from {} to {}", from, to);
545	
546	        List<LedgerEntry> entries = ledgerEntryMapper.findByDateRange(from, to);
547	
548	        StringBuilder csv = new StringBuilder();
549	        csv.append("id,payment_id,account_id,entry_type,amount,balance_after,description,reference_type,reference_id,created_at\n");
550	
551	        BigDecimal totalDebit = BigDecimal.ZERO;
552	        BigDecimal totalCredit = BigDecimal.ZERO;
553	        BigDecimal totalAdjustments = BigDecimal.ZERO;
554	        int adjustmentCount = 0;
555	        int paymentCount = 0;
556	        int refundCount = 0;
557	
558	        for (LedgerEntry entry : entries) {
559	            csv.append(entry.getId()).append(',')
560	                    .append(entry.getPaymentId()).append(',')
561	                    .append(entry.getAccountId()).append(',')
562	                    .append(entry.getEntryType()).append(',')
563	                    .append(entry.getAmount()).append(',')
564	                    .append(entry.getBalanceAfter()).append(',')
565	                    .append(escapeCsv(entry.getDescription())).append(',')
566	                    .append(entry.getReferenceType()).append(',')
567	                    .append(entry.getReferenceId()).append(',')
568	                    .append(entry.getCreatedAt()).append('\n');
569	
570	            if (entry.getEntryType() == LedgerEntryType.DEBIT) {
571	                totalDebit = totalDebit.add(entry.getAmount());
572	            } else {
573	                totalCredit = totalCredit.add(entry.getAmount());
574	            }
575	
576	            // Track adjustments vs payments vs refunds
577	            String refType = entry.getReferenceType();
578	            if ("ADJUSTMENT".equalsIgnoreCase(refType)) {
579	                adjustmentCount++;
580	                totalAdjustments = totalAdjustments.add(entry.getAmount());
581	            } else if ("REFUND".equalsIgnoreCase(refType) || (entry.getDescription() != null && entry.getDescription().toLowerCase().contains("refund"))) {
582	                refundCount++;
583	            } else {
584	                paymentCount++;
585	            }
586	        }
587	
588	        csv.append('\n');
589	        csv.append("SUMMARY\n");
590	        csv.append("Period,").append(from).append(" to ").append(to).append('\n');
591	        csv.append("Total Entries,").append(entries.size()).append('\n');
592	        csv.append("Total Payments,").append(paymentCount).append('\n');
593	        csv.append("Total Refunds,").append(refundCount).append('\n');
594	        csv.append("Total Adjustments,").append(adjustmentCount).append('\n');
595	        csv.append("Adjustment Amount,").append(totalAdjustments).append('\n');
596	        csv.append("Total Debits,").append(totalDebit).append('\n');
597	        csv.append("Total Credits,").append(totalCredit).append('\n');
598	        csv.append("Net,").append(totalCredit.subtract(totalDebit)).append('\n');
599	
600	        log.info("Reconciliation export generated: {} entries", entries.size());
601	        return csv.toString().getBytes(StandardCharsets.UTF_8);
602	    }
