75	    public DeliveryJob createJob(DeliveryJobCreateDTO dto, Long dispatcherId) {
76	        log.info("Creating delivery job for dispatcherId={}", dispatcherId);
77	
78	        ShippingRuleService.ValidationResult validation = shippingRuleService.validateAddress(
79	                dto.getReceiverState(), dto.getReceiverZip(), dto.getWeightLbs(), dto.getOrderAmount());
80	        if (!validation.isValid()) {
81	            log.warn("Address validation failed: {}", validation.getReason());
82	            throw new AddressValidationException("Address validation failed", validation.getReason());
83	        }
84	
85	        String trackingNumber = "DO-" + System.currentTimeMillis() + "-" + (1000 + new Random().nextInt(9000));
86	
87	        DeliveryJob job = new DeliveryJob();
88	        job.setTrackingNumber(trackingNumber);
89	        job.setStatus(JobStatus.CREATED);
90	        job.setDispatcherId(dispatcherId);
91	        job.setSenderName(dto.getSenderName());
92	        job.setSenderAddress(dto.getSenderAddress());
93	        job.setReceiverName(dto.getReceiverName());
94	        job.setReceiverAddress(dto.getReceiverAddress());
95	        job.setReceiverState(dto.getReceiverState());
96	        job.setReceiverZip(dto.getReceiverZip());
97	        job.setWeightLbs(dto.getWeightLbs());
98	        job.setOrderAmount(dto.getOrderAmount());
99	        job.setAdminOverride(false);
100	        job.setCreatedAt(LocalDateTime.now());
101	        job.setUpdatedAt(LocalDateTime.now());
102	        job.setVersion(1);
103	
104	        if (dto.getSenderPhone() != null) {
105	            job.setSenderPhoneEncrypted(fieldEncryptionService.encrypt(dto.getSenderPhone()));
106	        }
107	        if (dto.getReceiverPhone() != null) {
108	            job.setReceiverPhoneEncrypted(fieldEncryptionService.encrypt(dto.getReceiverPhone()));
109	        }
110	
111	        deliveryJobMapper.insert(job);
112	        log.info("Delivery job inserted with id={}, trackingNumber={}", job.getId(), trackingNumber);
113	
114	        FulfillmentEvent event = new FulfillmentEvent();
115	        event.setJobId(job.getId());
116	        event.setEventType(EventType.STATUS_CHANGE);
117	        event.setNewStatus(JobStatus.CREATED);
118	        event.setActorId(dispatcherId);
119	        event.setCreatedAt(LocalDateTime.now());
120	        fulfillmentEventMapper.insert(event);
121	
122	        LocalDateTime now = LocalDateTime.now();
123	        job.setLastEventAt(now);
124	        deliveryJobMapper.updateLastEventAt(job.getId(), now);
125	
126	        log.info("Delivery job id={} created successfully", job.getId());
127	        indexJob(job);
128	        return job;
129	    }
