131	    public DeliveryJob assignCourier(Long jobId, Long courierId, Long actorId) {
132	        log.info("Assigning courier={} to jobId={} by actorId={}", courierId, jobId, actorId);
133	
134	        DeliveryJob job = deliveryJobMapper.findById(jobId);
135	        if (job == null) {
136	            throw new ResourceNotFoundException("Delivery job not found with id: " + jobId, "DeliveryJob", jobId);
137	        }
138	
139	        if (job.getStatus() != JobStatus.CREATED && job.getStatus() != JobStatus.MANUAL_VALIDATION) {
140	            throw new IllegalStateException(
141	                    "Cannot assign courier when job status is " + job.getStatus()
142	                            + ". Job must be in CREATED or MANUAL_VALIDATION status.");
143	        }
144	
145	        CreditLevelSnapshot creditLevel = creditLevelMapper.findByCourierId(courierId);
146	        if (creditLevel == null) {
147	            throw new ResourceNotFoundException("Credit level not found for courierId: " + courierId, "CreditLevelSnapshot", courierId);
148	        }
149	
150	        int activeJobs = deliveryJobMapper.countByCourierAndActiveStatuses(courierId);
151	        if (activeJobs >= creditLevel.getMaxConcurrent()) {
152	            log.warn("Courier {} has {} active jobs but max concurrent is {}",
153	                    courierId, activeJobs, creditLevel.getMaxConcurrent());
154	            throw new InsufficientCreditException(
155	                    "Courier has reached maximum concurrent jobs",
156	                    creditLevel.getLevel().name(),
157	                    creditLevel.getMaxConcurrent(),
158	                    activeJobs);
159	        }
160	
161	        deliveryJobMapper.updateCourier(jobId, courierId);
162	        job.setCourierId(courierId);
163	
164	        notificationService.notify(
165	                courierId,
166	                NotificationType.STATUS_CHANGE,
167	                "Job Assigned",
168	                "You have been assigned to delivery job " + job.getTrackingNumber(),
169	                "DeliveryJob",
170	                jobId);
171	
172	        log.info("Courier {} assigned to job {} successfully", courierId, jobId);
173	        indexJob(job);
174	        return job;
175	    }
