177	    public DeliveryJob transitionStatus(Long jobId, String newStatusStr, String comment,
178	                                         int expectedVersion, Long actorId) {
179	        log.info("Transitioning status for jobId={} to {} by actorId={}", jobId, newStatusStr, actorId);
180	
181	        DeliveryJob job = deliveryJobMapper.findById(jobId);
182	        if (job == null) {
183	            throw new ResourceNotFoundException("Delivery job not found with id: " + jobId, "DeliveryJob", jobId);
184	        }
185	
186	        JobStatus newStatus = JobStatus.valueOf(newStatusStr);
187	        JobStatus oldStatus = job.getStatus();
188	
189	        StatusTransitionValidator.validateJobTransition(oldStatus, newStatus);
190	
191	        if (newStatus == JobStatus.EXCEPTION && (comment == null || comment.isBlank())) {
192	            throw new IllegalArgumentException("Comment required for EXCEPTION status");
193	        }
194	
195	        int rowsUpdated = deliveryJobMapper.updateStatus(jobId, newStatusStr, expectedVersion);
196	        if (rowsUpdated == 0) {
197	            throw new OptimisticLockException(
198	                    "Delivery job was modified by another transaction",
199	                    "DeliveryJob", jobId, expectedVersion);
200	        }
201	
202	        FulfillmentEvent event = new FulfillmentEvent();
203	        event.setJobId(jobId);
204	        event.setEventType(EventType.STATUS_CHANGE);
205	        event.setOldStatus(oldStatus);
206	        event.setNewStatus(newStatus);
207	        event.setActorId(actorId);
208	        event.setComment(comment);
209	        event.setCreatedAt(LocalDateTime.now());
210	        fulfillmentEventMapper.insert(event);
211	
212	        LocalDateTime now = LocalDateTime.now();
213	        deliveryJobMapper.updateLastEventAt(jobId, now);
214	        job.setLastEventAt(now);
215	        job.setStatus(newStatus);
216	
217	        // Generate customer action token on DELIVERED (used for customer rating/appeal)
218	        if (newStatus == JobStatus.DELIVERED && job.getCustomerToken() == null) {
219	            String token = HmacUtil.computeHmac(
220	                    job.getTrackingNumber() + "|" + job.getReceiverName() + "|" + job.getId(),
221	                    hmacKey).substring(0, 32);
222	            job.setCustomerToken(token);
223	            deliveryJobMapper.updateCustomerToken(jobId, token);
224	            log.info("Customer token generated for job {}", job.getTrackingNumber());
225	        }
226	
227	        if (job.getDispatcherId() != null) {
228	            notificationService.notify(
229	                    job.getDispatcherId(),
230	                    NotificationType.STATUS_CHANGE,
231	                    "Job Status Updated",
232	                    "Job " + job.getTrackingNumber() + " status changed from " + oldStatus + " to " + newStatus,
233	                    "DeliveryJob",
234	                    jobId);
235	        }
236	        if (job.getCourierId() != null) {
237	            notificationService.notify(
238	                    job.getCourierId(),
239	                    NotificationType.STATUS_CHANGE,
240	                    "Job Status Updated",
241	                    "Job " + job.getTrackingNumber() + " status changed from " + oldStatus + " to " + newStatus,
242	                    "DeliveryJob",
243	                    jobId);
244	        }
245	
246	        log.info("Job {} transitioned from {} to {}", jobId, oldStatus, newStatus);
247	        indexJob(job);
248	        return job;
249	    }
