36	    @GetMapping("/metrics")
37	    public ResponseEntity<ApiResult<Map<String, Object>>> getDashboardMetrics(HttpSession session) {
38	        User currentUser = (User) session.getAttribute("currentUser");
39	        log.debug("Getting dashboard metrics for user '{}' with role {}", currentUser.getUsername(), currentUser.getRole());
40	
41	        Map<String, Object> metrics = new HashMap<>();
42	        Role role = currentUser.getRole();
43	
44	        if (role == Role.DISPATCHER) {
45	            metrics.put("activeJobs", deliveryJobService.listJobs(null, 0, 1).getTotalElements());
46	            metrics.put("exceptionsToday", deliveryJobService.listJobs("EXCEPTION", 0, 1).getTotalElements());
47	
48	        } else if (role == Role.AUDITOR) {
49	            metrics.put("pendingSettlements", paymentService.listPendingSettlements(0, 1).getTotalElements());
50	
51	        } else if (role == Role.COURIER) {
52	            metrics.put("creditLevel", credibilityService.getCourierCredibility(currentUser.getId()) != null
53	                    ? credibilityService.getCourierCredibility(currentUser.getId()).getLevel().name() : "D");
54	
55	        } else if (role == Role.OPS_MANAGER || role == Role.ADMIN) {
56	            metrics.put("totalJobs", deliveryJobService.listJobs(null, 0, 1).getTotalElements());
57	            metrics.put("pendingSettlements", paymentService.listPendingSettlements(0, 1).getTotalElements());
58	            metrics.put("exceptionsToday", deliveryJobService.listJobs("EXCEPTION", 0, 1).getTotalElements());
59	            metrics.put("idleJobs", deliveryJobService.getIdleJobs(20).size());
60	        }
61	
62	        metrics.put("role", role.name());
63	        return ResponseEntity.ok(ApiResult.success(metrics));
