68	        User currentUser = (User) session.getAttribute("currentUser");
69	        log.debug("Getting recent activity for user '{}'", currentUser.getUsername());
70	
71	        List<Map<String, Object>> activities = new ArrayList<>();
72	
73	        try {
74	            List<com.dispatchops.domain.model.DeliveryJob> recentJobs;
75	
76	            if (currentUser.getRole() == Role.COURIER) {
77	                // Couriers only see activity for their own assigned jobs
78	                recentJobs = deliveryJobService.listJobsByCourier(currentUser.getId(), 0, 20);
79	            } else {
80	                var result = deliveryJobService.listJobs(null, 0, 20);
81	                recentJobs = result != null ? result.getContent() : java.util.Collections.emptyList();
82	            }
83	
84	            if (recentJobs != null) {
85	                for (var dj : recentJobs) {
86	                    Map<String, Object> entry = new LinkedHashMap<>();
87	                    entry.put("timestamp", dj.getLastEventAt() != null ? dj.getLastEventAt().toString() : dj.getCreatedAt().toString());
88	                    entry.put("message", "Job " + dj.getTrackingNumber() + " status: " + dj.getStatus());
89	                    activities.add(entry);
90	                    if (activities.size() >= 20) break;
91	                }
92	            }
93	        } catch (Exception e) {
94	            log.warn("Unable to fetch recent job activity: {}", e.getMessage());
95	        }
96	
97	        return ResponseEntity.ok(ApiResult.success(activities));
98	    }
