30	    private static final Logger log = LoggerFactory.getLogger(NotificationService.class);
31	
32	    private final NotificationMapper notificationMapper;
33	    private final LanRelaySubMapper lanRelaySubMapper;
34	    private final LanRelayChannel lanRelayChannel;
35	
36	    @Value("${notification.poll.timeout-seconds:30}")
37	    private int pollTimeout;
38	
39	    private final ConcurrentHashMap<Long, List<DeferredResult<ApiResult<?>>>> pendingPolls =
40	            new ConcurrentHashMap<>();
41	
42	    public NotificationService(NotificationMapper notificationMapper,
43	                               LanRelaySubMapper lanRelaySubMapper,
44	                               LanRelayChannel lanRelayChannel) {
45	        this.notificationMapper = notificationMapper;
46	        this.lanRelaySubMapper = lanRelaySubMapper;
47	        this.lanRelayChannel = lanRelayChannel;
48	    }
49	
50	    public void notify(Long recipientId, NotificationType type, String title,
51	                       String body, String linkType, Long linkId) {
52	        log.debug("Creating notification for recipientId={}, type={}, title='{}'",
53	                recipientId, type, title);
54	
55	        Notification notification = new Notification();
56	        notification.setRecipientId(recipientId);
57	        notification.setType(type);
58	        notification.setTitle(title);
59	        notification.setBody(body);
60	        notification.setLinkType(linkType);
61	        notification.setLinkId(linkId);
62	        notification.setRead(false);
63	        notification.setCreatedAt(LocalDateTime.now());
64	
65	        notificationMapper.insert(notification);
66	        log.info("Notification id={} created for recipientId={}", notification.getId(), recipientId);
67	
68	        // Relay to LAN if enabled (fail-safe, non-blocking)
69	        try {
70	            lanRelayChannel.relay(notification);
71	        } catch (Exception e) {
72	            log.warn("LAN relay failed for notification id={}: {}", notification.getId(), e.getMessage());
73	        }
74	
75	        resolvePendingPolls(recipientId, Collections.singletonList(notification));
76	    }
77	
78	    public void notifyAll(List<Long> recipientIds, NotificationType type, String title,
79	                          String body, String linkType, Long linkId) {
80	        log.debug("Sending notification to {} recipients, type={}, title='{}'",
81	                recipientIds.size(), type, title);
82	
83	        for (Long recipientId : recipientIds) {
84	            notify(recipientId, type, title, body, linkType, linkId);
85	        }
86	    }
87	
88	    @Transactional(readOnly = true)
89	    public PageResult<Notification> getInbox(Long userId, Boolean readFilter, int page, int size) {
90	        log.debug("Fetching inbox for userId={}, readFilter={}, page={}, size={}",
91	                userId, readFilter, page, size);
92	
93	        int offset = page * size;
94	
95	        List<Notification> notifications;
96	        long total;
97	
98	        if (readFilter != null) {
99	            if (readFilter) {
100	                // Fetch read notifications - use full list and filter
101	                List<Notification> all = notificationMapper.findByRecipientId(userId, offset, size);
102	                notifications = new ArrayList<>();
103	                for (Notification n : all) {
104	                    if (n.isRead()) {
105	                        notifications.add(n);
106	                    }
107	                }
108	                total = notifications.size();
109	            } else {
110	                // Fetch unread notifications
111	                List<Notification> unread = notificationMapper.findUnreadByRecipientId(userId);
112	                total = unread.size();
113	                int fromIndex = Math.min(offset, unread.size());
114	                int toIndex = Math.min(offset + size, unread.size());
115	                notifications = unread.subList(fromIndex, toIndex);
116	            }
117	        } else {
118	            notifications = notificationMapper.findByRecipientId(userId, offset, size);
119	            total = notificationMapper.countByRecipientId(userId);
120	        }
121	
122	        return new PageResult<>(notifications, page, size, total);
123	    }
124	
125	    @Transactional(readOnly = true)
126	    public int getUnreadCount(Long userId) {
127	        log.debug("Fetching unread count for userId={}", userId);
128	        return notificationMapper.countUnread(userId);
129	    }
130	
131	    public void markAsRead(Long userId, Long notificationId) {
132	        log.debug("Marking notification id={} as read for userId={}", notificationId, userId);
133	
134	        Notification notification = notificationMapper.findById(notificationId);
135	        if (notification == null) {
136	            throw new ResourceNotFoundException(
137	                    "Notification not found with id: " + notificationId,
138	                    "Notification", notificationId);
139	        }
140	
141	        if (!notification.getRecipientId().equals(userId)) {
142	            throw new PermissionDeniedException(
143	                    "Notification " + notificationId + " does not belong to user " + userId);
144	        }
145	
146	        notificationMapper.markRead(notificationId);
147	        log.info("Notification id={} marked as read", notificationId);
148	    }
149	
150	    public void markAllAsRead(Long userId) {
151	        log.debug("Marking all notifications as read for userId={}", userId);
152	        int count = notificationMapper.markAllRead(userId);
153	        log.info("Marked {} notifications as read for userId={}", count, userId);
154	    }
155	
156	    public void registerPoll(Long userId, DeferredResult<ApiResult<?>> result) {
157	        log.debug("Registering long-poll for userId={}, timeout={}s", userId, pollTimeout);
158	
159	        List<DeferredResult<ApiResult<?>>> userPolls =
160	                pendingPolls.computeIfAbsent(userId, k -> new CopyOnWriteArrayList<>());
161	        userPolls.add(result);
162	
163	        result.onTimeout(() -> {
164	            log.debug("Long-poll timed out for userId={}", userId);
165	            result.setResult(ApiResult.success(Collections.emptyList()));
166	            List<DeferredResult<ApiResult<?>>> polls = pendingPolls.get(userId);
167	            if (polls != null) {
168	                polls.remove(result);
169	                if (polls.isEmpty()) {
170	                    pendingPolls.remove(userId);
171	                }
172	            }
173	        });
174	
175	        result.onCompletion(() -> {
176	            List<DeferredResult<ApiResult<?>>> polls = pendingPolls.get(userId);
177	            if (polls != null) {
178	                polls.remove(result);
179	                if (polls.isEmpty()) {
180	                    pendingPolls.remove(userId);
181	                }
182	            }
183	        });
184	    }
185	
186	    public void resolvePendingPolls(Long userId, List<Notification> newNotifications) {
187	        List<DeferredResult<ApiResult<?>>> userPolls = pendingPolls.remove(userId);
188	        if (userPolls == null || userPolls.isEmpty()) {
189	            log.debug("No pending polls for userId={}", userId);
190	            return;
191	        }
192	
193	        log.debug("Resolving {} pending poll(s) for userId={} with {} notification(s)",
194	                userPolls.size(), userId, newNotifications.size());
195	
196	        for (DeferredResult<ApiResult<?>> poll : userPolls) {
197	            poll.setResult(ApiResult.success(newNotifications));
198	        }
199	    }
200	}
