39	    public ResponseEntity<ApiResult<CredibilityRating>> submitRating(
40	            @Valid @RequestBody RatingSubmitDTO dto,
41	            HttpSession session) {
42	        User currentUser = (User) session.getAttribute("currentUser");
43	        log.info("User '{}' submitting rating for job {}", currentUser.getUsername(), dto.getJobId());
44	        CredibilityRating rating = credibilityService.submitRating(
45	                dto.getJobId(), dto.getTimeliness(), dto.getAttitude(), dto.getAccuracy(),
