91	    @PostMapping("/ratings/customer")
92	    public ResponseEntity<ApiResult<CredibilityRating>> submitCustomerRating(
93	            @Valid @RequestBody com.dispatchops.web.dto.CustomerRatingDTO dto,
94	            jakarta.servlet.http.HttpServletRequest request) {
95	        String ip = request.getRemoteAddr();
96	        if (isRateLimited(ip)) {
97	            log.warn("Customer rate limit exceeded for IP={}, tracking={}", ip, dto.getTrackingNumber());
98	            return ResponseEntity.status(429).body(ApiResult.error(429, "Too many requests. Please try again later."));
99	        }
100	        log.info("Customer rating submission for tracking={} from IP={}", dto.getTrackingNumber(), ip);
101	        try {
102	            CredibilityRating rating = credibilityService.submitCustomerRating(
103	                    dto.getTrackingNumber(), dto.getReceiverName(), dto.getCustomerToken(),
104	                    dto.getTimeliness(), dto.getAttitude(), dto.getAccuracy(), dto.getComment());
105	            return ResponseEntity.status(201).body(ApiResult.success(rating));
106	        } catch (com.dispatchops.domain.exception.ResourceNotFoundException | com.dispatchops.domain.exception.PermissionDeniedException e) {
107	            // Normalize to prevent enumeration: don't distinguish not-found from permission-denied
108	            return ResponseEntity.status(422).body(ApiResult.error(422, "Unable to process rating. Verify tracking number and receiver name."));
109	        }
110	    }
