31	@Service
32	@Transactional
33	public class TaskService {
34	
35	    private static final Logger log = LoggerFactory.getLogger(TaskService.class);
36	    private static final Pattern MENTION_PATTERN = Pattern.compile("@(\\w+)");
37	
38	    private final InternalTaskMapper internalTaskMapper;
39	    private final TaskRecipientMapper taskRecipientMapper;
40	    private final TaskCommentMapper taskCommentMapper;
41	    private final NotificationService notificationService;
42	    private final DeliveryJobMapper deliveryJobMapper;
43	    private final UserMapper userMapper;
44	    private final SearchService searchService;
45	
46	    public TaskService(InternalTaskMapper internalTaskMapper,
47	                       TaskRecipientMapper taskRecipientMapper,
48	                       TaskCommentMapper taskCommentMapper,
49	                       NotificationService notificationService,
50	                       DeliveryJobMapper deliveryJobMapper,
51	                       UserMapper userMapper,
52	                       SearchService searchService) {
53	        this.internalTaskMapper = internalTaskMapper;
54	        this.taskRecipientMapper = taskRecipientMapper;
55	        this.taskCommentMapper = taskCommentMapper;
56	        this.notificationService = notificationService;
57	        this.deliveryJobMapper = deliveryJobMapper;
58	        this.userMapper = userMapper;
59	        this.searchService = searchService;
60	    }
61	
62	    private void indexTask(InternalTask task) {
63	        try {
64	            searchService.indexEntity("TASK", task.getId(), task.getTitle(),
65	                    task.getBody() != null ? task.getBody() : "",
66	                    task.getStatus() != null ? task.getStatus().name() : "", task.getCreatorId());
67	        } catch (Exception e) {
68	            log.warn("Failed to index task {}: {}", task.getId(), e.getMessage());
69	        }
70	    }
71	
72	    public InternalTask createTask(TaskCreateDTO dto, Long creatorId) {
73	        log.info("Creating task '{}' by creatorId={}", dto.getTitle(), creatorId);
74	
75	        if (dto.getJobId() != null) {
76	            if (deliveryJobMapper.findById(dto.getJobId()) == null) {
77	                throw new ResourceNotFoundException(
78	                        "Delivery job not found with id: " + dto.getJobId(), "DeliveryJob", dto.getJobId());
79	            }
80	        }
81	
82	        InternalTask task = new InternalTask();
83	        task.setTitle(dto.getTitle());
84	        task.setBody(dto.getBody());
85	        task.setStatus(TaskStatus.TODO);
86	        task.setCreatorId(creatorId);
87	        task.setAssigneeId(dto.getAssigneeId());
88	        task.setDueTime(dto.getDueTime());
89	        task.setShowOnCalendar(dto.isShowOnCalendar());
90	        task.setJobId(dto.getJobId());
91	        task.setCreatedAt(LocalDateTime.now());
92	        task.setUpdatedAt(LocalDateTime.now());
93	        task.setVersion(0);
94	
95	        internalTaskMapper.insert(task);
96	        log.info("Task inserted with id={}", task.getId());
97	
98	        TaskRecipient assigneeRecipient = new TaskRecipient();
99	        assigneeRecipient.setTaskId(task.getId());
100	        assigneeRecipient.setUserId(dto.getAssigneeId());
101	        assigneeRecipient.setInboxType(InboxType.TODO);
102	        assigneeRecipient.setCreatedAt(LocalDateTime.now());
103	        taskRecipientMapper.insert(assigneeRecipient);
104	
105	        if (dto.getCcUserIds() != null) {
106	            for (Long ccUserId : dto.getCcUserIds()) {
107	                TaskRecipient ccRecipient = new TaskRecipient();
108	                ccRecipient.setTaskId(task.getId());
109	                ccRecipient.setUserId(ccUserId);
110	                ccRecipient.setInboxType(InboxType.CC);
111	                ccRecipient.setCreatedAt(LocalDateTime.now());
112	                taskRecipientMapper.insert(ccRecipient);
113	            }
114	        }
115	
116	        notificationService.notify(
117	                dto.getAssigneeId(),
118	                NotificationType.TASK_ASSIGNED,
119	                "New Task Assigned",
120	                "You have been assigned task: " + dto.getTitle(),
121	                "InternalTask",
122	                task.getId());
123	
124	        log.info("Task id={} created successfully with {} CC recipients",
125	                task.getId(), dto.getCcUserIds() != null ? dto.getCcUserIds().size() : 0);
126	        indexTask(task);
127	        return task;
128	    }
129	
130	    public InternalTask transitionStatus(Long taskId, String newStatusStr, String comment,
131	                                          int expectedVersion, Long actorId) {
132	        log.info("Transitioning status for taskId={} to {} by actorId={}", taskId, newStatusStr, actorId);
133	
134	        InternalTask task = internalTaskMapper.findById(taskId);
135	        if (task == null) {
136	            throw new ResourceNotFoundException("Task not found with id: " + taskId, "InternalTask", taskId);
137	        }
138	
139	        TaskStatus newStatus = TaskStatus.valueOf(newStatusStr);
140	        TaskStatus oldStatus = task.getStatus();
141	
142	        StatusTransitionValidator.validateTaskTransition(oldStatus, newStatus);
143	
144	        if ((newStatus == TaskStatus.BLOCKED || newStatus == TaskStatus.EXCEPTION)
145	                && (comment == null || comment.trim().length() < 10)) {
146	            throw new IllegalArgumentException(
147	                    "Comment of at least 10 characters required for " + newStatus + " status");
148	        }
149	
150	        int rowsUpdated = internalTaskMapper.updateStatus(taskId, newStatusStr, expectedVersion);
151	        if (rowsUpdated == 0) {
152	            throw new OptimisticLockException(
153	                    "Task was modified by another transaction",
154	                    "InternalTask", taskId, expectedVersion);
155	        }
156	
157	        if (newStatus == TaskStatus.DONE) {
158	            taskRecipientMapper.updateInboxType(taskId, task.getAssigneeId(),
159	                    InboxType.TODO.name(), InboxType.DONE.name());
160	        }
161	
162	        if (comment != null && !comment.isBlank()) {
163	            TaskComment taskComment = new TaskComment();
164	            taskComment.setTaskId(taskId);
165	            taskComment.setAuthorId(actorId);
166	            taskComment.setBody("[Status: " + oldStatus + " -> " + newStatus + "] " + comment);
167	            taskComment.setCreatedAt(LocalDateTime.now());
168	            taskCommentMapper.insert(taskComment);
169	        }
170	
171	        task.setStatus(newStatus);
172	
173	        List<TaskRecipient> recipients = taskRecipientMapper.findByTaskId(taskId);
174	        for (TaskRecipient recipient : recipients) {
175	            if (!recipient.getUserId().equals(actorId)) {
176	                notificationService.notify(
177	                        recipient.getUserId(),
178	                        NotificationType.STATUS_CHANGE,
179	                        "Task Status Updated",
180	                        "Task '" + task.getTitle() + "' status changed from " + oldStatus + " to " + newStatus,
181	                        "InternalTask",
182	                        taskId);
183	            }
184	        }
185	
186	        log.info("Task {} transitioned from {} to {}", taskId, oldStatus, newStatus);
187	        indexTask(task);
188	        return task;
189	    }
190	
191	    public TaskComment addComment(Long taskId, String body, Long authorId) {
192	        log.info("Adding comment to taskId={} by authorId={}", taskId, authorId);
193	
194	        InternalTask task = internalTaskMapper.findById(taskId);
195	        if (task == null) {
196	            throw new ResourceNotFoundException("Task not found with id: " + taskId, "InternalTask", taskId);
197	        }
198	
199	        TaskComment comment = new TaskComment();
200	        comment.setTaskId(taskId);
201	        comment.setAuthorId(authorId);
202	        comment.setBody(body);
203	        comment.setCreatedAt(LocalDateTime.now());
204	        taskCommentMapper.insert(comment);
205	        log.info("Comment id={} added to task {}", comment.getId(), taskId);
206	
207	        Matcher matcher = MENTION_PATTERN.matcher(body);
208	        List<String> mentionedUsernames = new ArrayList<>();
209	        while (matcher.find()) {
210	            mentionedUsernames.add(matcher.group(1));
211	        }
212	
213	        for (String username : mentionedUsernames) {
214	            User mentionedUser = userMapper.findByUsername(username);
215	            if (mentionedUser != null) {
216	                notificationService.notify(
217	                        mentionedUser.getId(),
218	                        NotificationType.MENTION,
219	                        "You were mentioned",
220	                        "You were mentioned in a comment on task: " + task.getTitle(),
221	                        "InternalTask",
222	                        taskId);
223	                log.debug("Mention notification sent to user '{}'", username);
224	            }
225	        }
226	
227	        return comment;
228	    }
