230	    @Transactional(readOnly = true)
231	    public PageResult<InternalTask> getInbox(Long userId, String inboxType, int page, int size) {
232	        log.debug("Fetching inbox for userId={}, inboxType={}, page={}, size={}", userId, inboxType, page, size);
233	
234	        int offset = page * size;
235	        List<TaskRecipient> recipients = taskRecipientMapper.findByUserAndInboxType(userId, inboxType, offset, size);
236	        int total = taskRecipientMapper.countByUserAndInboxType(userId, inboxType);
237	
238	        List<InternalTask> tasks = new ArrayList<>();
239	        for (TaskRecipient recipient : recipients) {
240	            InternalTask task = internalTaskMapper.findById(recipient.getTaskId());
241	            if (task != null) {
242	                tasks.add(task);
243	            }
244	        }
245	
246	        return new PageResult<>(tasks, page, size, total);
247	    }
