1	package com.dispatchops.infrastructure.security;
2	
3	import org.junit.jupiter.api.Test;
4	
5	import static org.junit.jupiter.api.Assertions.*;
6	
7	/**
8	 * TDD tests for AES encryption utility.
9	 */
10	class AesUtilTest {
11	
12	    private static final String TEST_KEY = "0123456789abcdef0123456789abcdef0123456789abcdef0123456789abcdef";
13	
14	    @Test
15	    void encryptDecryptRoundTrip() {
16	        String plaintext = "Hello, World!";
17	        byte[] encrypted = AesUtil.encryptString(plaintext, TEST_KEY);
18	        assertNotNull(encrypted);
19	        assertTrue(encrypted.length > 0);
20	
21	        String decrypted = AesUtil.decryptString(encrypted, TEST_KEY);
22	        assertEquals(plaintext, decrypted);
23	    }
24	
25	    @Test
26	    void encryptDecryptWithUnicodeData() {
27	        String plaintext = "Test with special chars: cafe\u0301 naif \u00FC \u00F1";
28	        byte[] encrypted = AesUtil.encryptString(plaintext, TEST_KEY);
29	        String decrypted = AesUtil.decryptString(encrypted, TEST_KEY);
30	        assertEquals(plaintext, decrypted);
31	    }
32	
33	    @Test
34	    void encryptProducesDifferentCiphertextEachTime() {
35	        String plaintext = "same data";
36	        byte[] enc1 = AesUtil.encryptString(plaintext, TEST_KEY);
37	        byte[] enc2 = AesUtil.encryptString(plaintext, TEST_KEY);
38	        // Different IVs should produce different ciphertexts
39	        assertNotEquals(bytesToHex(enc1), bytesToHex(enc2));
40	    }
41	
42	    @Test
43	    void decryptWithWrongKeyProducesDifferentResult() {
44	        String plaintext = "Secret data";
45	        byte[] encrypted = AesUtil.encryptString(plaintext, TEST_KEY);
46	        String wrongKey = "fedcba9876543210fedcba9876543210fedcba9876543210fedcba9876543210";
47	        // With wrong key, decryption either throws or produces garbage (not the original)
48	        try {
49	            String result = AesUtil.decryptString(encrypted, wrongKey);
50	            assertNotEquals(plaintext, result, "Decryption with wrong key should not produce the original plaintext");
51	        } catch (RuntimeException e) {
52	            // This is also acceptable - wrong key can cause padding errors
53	        }
54	    }
55	
56	    @Test
57	    void encryptNullReturnsNull() {
58	        assertNull(AesUtil.encryptString(null, TEST_KEY));
59	    }
60	
61	    @Test
62	    void decryptNullReturnsNull() {
63	        assertNull(AesUtil.decryptString(null, TEST_KEY));
64	    }
65	
66	    @Test
67	    void hexToBytesConversion() {
68	        byte[] bytes = AesUtil.hexToBytes("48656c6c6f");
69	        assertEquals("Hello", new String(bytes));
70	    }
71	
72	    private String bytesToHex(byte[] bytes) {
73	        StringBuilder sb = new StringBuilder();
74	        for (byte b : bytes) {
75	            sb.append(String.format("%02x", b));
76	        }
77	        return sb.toString();
78	    }
79	}
