117	    /**
118	     * Validates the customer action token against the stored token on the job.
119	     * Recomputes the expected token from job data + HMAC key and compares using timing-safe equality.
120	     */
121	    private void validateCustomerToken(DeliveryJob job, String customerToken) {
122	        if (job.getCustomerToken() == null) {
123	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
124	                    "Customer action token not available for this job");
125	        }
126	        String expected = HmacUtil.computeHmac(
127	                job.getTrackingNumber() + "|" + job.getReceiverName() + "|" + job.getId(),
128	                hmacKey).substring(0, 32);
129	        if (!java.security.MessageDigest.isEqual(
130	                expected.getBytes(java.nio.charset.StandardCharsets.UTF_8),
131	                customerToken.getBytes(java.nio.charset.StandardCharsets.UTF_8))) {
132	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
133	                    "Invalid customer action token");
134	        }
135	    }
