152	            throw new IllegalStateException("Cannot rate a job that is not DELIVERED. Current: " + job.getStatus());
153	        }
154	
155	        // Validate receiver name matches - use generic error to prevent enumeration
156	        if (!job.getReceiverName().equalsIgnoreCase(receiverName)) {
157	            throw new com.dispatchops.domain.exception.PermissionDeniedException(
158	                    "Invalid tracking number or receiver name");
159	        }
160	
161	        // Validate customer action token
162	        validateCustomerToken(job, customerToken);
163	
164	        // Customer ratings: rater_id is NULL (no user account), rater_type=CUSTOMER.
165	        // customer_name provides the attribution identity. Unique per (job_id, customer_name).
166	        CredibilityRating rating = new CredibilityRating();
167	        rating.setCourierId(job.getCourierId());
