181	        } catch (org.springframework.dao.DuplicateKeyException e) {
182	            throw new com.dispatchops.domain.exception.IdempotencyViolationException(
183	                    "A customer rating for this job has already been submitted", job.getId());
184	        }
185	        log.info("Customer rating id={} created for job {} by customer '{}'", rating.getId(), job.getId(), receiverName);
