196	     */
197	    public Appeal fileCustomerAppeal(String trackingNumber, String receiverName, String customerToken,
198	                                      Long ratingId, String reason) {
199	        log.info("Customer appeal for trackingNumber={}", trackingNumber);
200	
201	        DeliveryJob job = deliveryJobMapper.findByTrackingNumber(trackingNumber);
202	        if (job == null) {
203	            throw new ResourceNotFoundException("Job not found: " + trackingNumber, "DeliveryJob", trackingNumber);
204	        }
205	        if (!job.getReceiverName().equalsIgnoreCase(receiverName)) {
206	            throw new com.dispatchops.domain.exception.PermissionDeniedException("Invalid tracking number or receiver name");
207	        }
208	
209	        // Validate customer action token
210	        validateCustomerToken(job, customerToken);
211	
212	        // Validate rating belongs to the resolved job (prevents cross-object targeting)
213	        Long courierId = null;
214	        if (ratingId != null) {
215	            CredibilityRating rating = credibilityRatingMapper.findById(ratingId);
216	            if (rating == null) {
217	                throw new ResourceNotFoundException("Rating not found: " + ratingId, "CredibilityRating", ratingId);
218	            }
219	            if (!rating.getJobId().equals(job.getId())) {
220	                throw new com.dispatchops.domain.exception.PermissionDeniedException(
221	                        "Rating " + ratingId + " does not belong to job " + job.getTrackingNumber());
222	            }
223	            courierId = rating.getCourierId();
224	        }
225	        if (courierId == null) {
226	            courierId = job.getCourierId();
227	        }
228	
229	        String auditReason = "[Customer: " + receiverName + "] " + reason;
230	        return fileAppeal(ratingId, null, auditReason, courierId);
