233	    public Appeal fileAppeal(Long ratingId, Long violationId, String reason, Long courierId) {
234	        log.info("Filing appeal by courierId={}, ratingId={}, violationId={}", courierId, ratingId, violationId);
235	
236	        // Exactly one of ratingId or violationId must be provided
237	        if (ratingId == null && violationId == null) {
238	            throw new IllegalArgumentException("Appeal must reference either a ratingId or a violationId");
239	        }
240	        if (ratingId != null && violationId != null) {
241	            throw new IllegalArgumentException("Appeal must reference exactly one of ratingId or violationId, not both");
242	        }
243	
244	        LocalDateTime now = LocalDateTime.now();
245	
246	        if (ratingId != null) {
247	            CredibilityRating rating = credibilityRatingMapper.findById(ratingId);
248	            if (rating == null) {
249	                throw new ResourceNotFoundException("Rating not found with id: " + ratingId, "CredibilityRating", ratingId);
250	            }
251	            // Ownership check: rating must be about this courier
252	            if (!rating.getCourierId().equals(courierId)) {
253	                throw new com.dispatchops.domain.exception.PermissionDeniedException(
254	                        "Rating " + ratingId + " does not belong to courier " + courierId);
255	            }
256	            if (rating.getCreatedAt().plusHours(APPEAL_WINDOW_HOURS).isBefore(now)) {
257	                throw new AppealWindowClosedException(
258	                        "Appeal window has closed. Ratings must be appealed within " + APPEAL_WINDOW_HOURS + " hours.");
259	            }
260	        }
261	
262	        if (violationId != null) {
263	            Violation violation = violationMapper.findById(violationId);
264	            if (violation == null) {
265	                throw new ResourceNotFoundException("Violation not found with id: " + violationId, "Violation", violationId);
266	            }
267	            // Ownership check: violation must be about this courier
268	            if (!violation.getCourierId().equals(courierId)) {
269	                throw new com.dispatchops.domain.exception.PermissionDeniedException(
270	                        "Violation " + violationId + " does not belong to courier " + courierId);
271	            }
272	            if (violation.getCreatedAt().plusHours(APPEAL_WINDOW_HOURS).isBefore(now)) {
273	                throw new AppealWindowClosedException(
274	                        "Appeal window has closed. Violations must be appealed within " + APPEAL_WINDOW_HOURS + " hours.");
275	            }
276	        }
277	
278	        Appeal appeal = new Appeal();
279	        appeal.setRatingId(ratingId);
280	        appeal.setViolationId(violationId);
281	        appeal.setCourierId(courierId);
282	        appeal.setReason(reason);
283	        appeal.setStatus(AppealStatus.PENDING);
284	        appeal.setCreatedAt(LocalDateTime.now());
285	
286	        appealMapper.insert(appeal);
287	        log.info("Appeal id={} filed by courier {}", appeal.getId(), courierId);
288	
289	        List<com.dispatchops.domain.model.User> admins = userMapper.findByRole(Role.ADMIN.name());
290	        for (com.dispatchops.domain.model.User admin : admins) {
291	            notificationService.notify(
292	                    admin.getId(),
293	                    NotificationType.APPEAL_UPDATE,
294	                    "New Appeal Filed",
295	                    "Courier has filed an appeal requiring review",
296	                    "Appeal",
297	                    appeal.getId());
298	        }
299	
300	        return appeal;
301	    }
302	
303	    public Appeal resolveAppeal(Long appealId, String statusStr, String comment, Long reviewerId) {
304	        log.info("Resolving appeal id={} with status={} by reviewerId={}", appealId, statusStr, reviewerId);
305	
306	        Appeal appeal = appealMapper.findById(appealId);
307	        if (appeal == null) {
308	            throw new ResourceNotFoundException("Appeal not found with id: " + appealId, "Appeal", appealId);
309	        }
310	
311	        AppealStatus status = AppealStatus.valueOf(statusStr);
312	        LocalDateTime now = LocalDateTime.now();
313	
314	        int rowsUpdated = appealMapper.resolve(appealId, statusStr, reviewerId, comment, now);
315	        if (rowsUpdated == 0) {
