3	<!DOCTYPE html>
4	<html lang="en">
5	<head>
6	    <meta charset="UTF-8">
7	    <meta name="viewport" content="width=device-width, initial-scale=1.0">
8	    <title>DispatchOps - Login</title>
9	    <link rel="stylesheet" href="/static/css/fluent-tokens.css">
10	    <link rel="stylesheet" href="/static/css/app.css">
11	</head>
12	<body>
13	    <div class="login-page">
14	        <div class="card login-card">
15	            <div class="login-title">
16	                <h1>DispatchOps</h1>
17	                <p class="text-secondary">Courier Operations & Settlement</p>
18	            </div>
19	
20	            <div class="login-error hidden" id="login-error"></div>
21	            <div class="login-error hidden" id="lockout-message">
22	                Account is locked. Try again in <span id="lockout-countdown"></span>.
23	            </div>
24	
25	            <form id="login-form">
26	                <div class="form-group">
27	                    <label class="form-label" for="username">Username</label>
28	                    <input type="text" class="form-input" id="username" name="username"
29	                           placeholder="Enter your username" required autofocus>
30	                </div>
31	                <div class="form-group">
32	                    <label class="form-label" for="password">Password</label>
33	                    <input type="password" class="form-input" id="password" name="password"
34	                           placeholder="Enter your password" required>
35	                </div>
36	                <button type="submit" class="fluent-btn fluent-btn-primary w-full" id="login-btn"
37	                        style="min-height:40px; margin-top: var(--fluent-spacing-s);">
38	                    Log In
39	                </button>
40	            </form>
41	        </div>
42	    </div>
43	
44	    <div class="toast-container" id="toast-container"></div>
45	
46	    <script src="/static/js/vendor/jquery-3.7.1.min.js"></script>
47	    <script src="/static/js/common/util.js"></script>
48	    <script src="/static/js/common/toast.js"></script>
49	    <script>
50	    $(function() {
51	        var lockoutTimer = null;
52	
53	        // Check URL for expired session
54	        if (window.location.search.indexOf('expired=true') !== -1) {
55	            $('#login-error').text('Your session has expired. Please log in again.').removeClass('hidden');
56	        }
57	
58	        $('#login-form').on('submit', function(e) {
59	            e.preventDefault();
60	            var username = $('#username').val().trim();
61	            var password = $('#password').val();
62	
63	            if (!username || !password) {
64	                $('#login-error').text('Please enter both username and password.').removeClass('hidden');
65	                return;
66	            }
67	
68	            $('#login-btn').prop('disabled', true).text('Logging in...');
69	            $('#login-error').addClass('hidden');
70	            $('#lockout-message').addClass('hidden');
71	
72	            $.ajax({
73	                url: '/api/auth/login',
74	                method: 'POST',
75	                contentType: 'application/json',
76	                data: JSON.stringify({ username: username, password: password }),
77	                dataType: 'json'
78	            }).done(function(resp) {
79	                if (resp.code === 200) {
80	                    if (resp.data && resp.data.mustChangePassword) {
81	                        window.location.href = '/change-password';
82	                    } else {
83	                        window.location.href = '/dashboard';
84	                    }
85	                } else {
86	                    $('#login-error').text(resp.message || 'Login failed.').removeClass('hidden');
87	                    $('#login-btn').prop('disabled', false).text('Log In');
88	                }
89	            }).fail(function(xhr) {
90	                $('#login-btn').prop('disabled', false).text('Log In');
91	
92	                if (xhr.status === 423) {
93	                    // Account locked
94	                    var resp = xhr.responseJSON;
95	                    var expiry = resp && resp.data && resp.data.lockoutExpiry;
96	                    if (expiry) {
97	                        startLockoutCountdown(new Date(expiry));
98	                    } else {
99	                        $('#lockout-message').removeClass('hidden');
100	                        $('#lockout-countdown').text('15:00');
101	                    }
102	                } else if (xhr.status === 401) {
103	                    var resp = xhr.responseJSON;
104	                    var msg = resp && resp.message ? resp.message : 'Invalid username or password.';
105	                    if (resp && resp.data && resp.data.remainingAttempts != null) {
106	                        msg += ' (' + resp.data.remainingAttempts + ' attempts remaining)';
107	                    }
108	                    $('#login-error').text(msg).removeClass('hidden');
109	                } else {
110	                    $('#login-error').text('An error occurred. Please try again.').removeClass('hidden');
111	                }
112	            });
113	        });
114	
115	        function startLockoutCountdown(expiryDate) {
116	            $('#lockout-message').removeClass('hidden');
117	            $('#login-error').addClass('hidden');
118	            $('#login-btn').prop('disabled', true);
119	
120	            if (lockoutTimer) clearInterval(lockoutTimer);
121	
122	            lockoutTimer = setInterval(function() {
123	                var remaining = expiryDate.getTime() - Date.now();
124	                if (remaining <= 0) {
125	                    clearInterval(lockoutTimer);
126	                    $('#lockout-message').addClass('hidden');
127	                    $('#login-btn').prop('disabled', false).text('Log In');
128	                    return;
129	                }
130	                var min = Math.floor(remaining / 60000);
131	                var sec = Math.floor((remaining % 60000) / 1000);
132	                $('#lockout-countdown').text(App.util.padZero(min) + ':' + App.util.padZero(sec));
133	            }, 1000);
134	        }
135	    });
136	    </script>
137	</body>
138	</html>
