1	package com.dispatchops.web.interceptor;
2	
3	import com.dispatchops.domain.model.User;
4	import com.dispatchops.web.dto.ApiResult;
5	import com.fasterxml.jackson.databind.ObjectMapper;
6	import jakarta.servlet.http.HttpServletRequest;
7	import jakarta.servlet.http.HttpServletResponse;
8	import jakarta.servlet.http.HttpSession;
9	import org.springframework.stereotype.Component;
10	import org.springframework.web.servlet.HandlerInterceptor;
11	
12	import java.util.Set;
13	
14	@Component
15	public class AuthInterceptor implements HandlerInterceptor {
16	
17	    private final ObjectMapper objectMapper = new ObjectMapper();
18	
19	    /** Endpoints allowed even when must_change_password is set */
20	    private static final Set<String> PASSWORD_CHANGE_ALLOWED = Set.of(
21	            "/api/auth/logout", "/api/auth/me", "/api/auth/heartbeat"
22	    );
23	
24	    @Override
25	    public boolean preHandle(HttpServletRequest request, HttpServletResponse response, Object handler) throws Exception {
26	        String path = request.getRequestURI();
27	        if (path.startsWith("/api/auth/login")) {
28	            return true;
29	        }
30	
31	        HttpSession session = request.getSession(false);
32	        if (session == null || session.getAttribute("currentUser") == null) {
33	            response.setStatus(HttpServletResponse.SC_UNAUTHORIZED);
34	            response.setContentType("application/json");
35	            response.setCharacterEncoding("UTF-8");
36	            objectMapper.writeValue(response.getWriter(), ApiResult.error(401, "Authentication required"));
37	            return false;
38	        }
39	
40	        // Enforce must_change_password: block all endpoints except password change and auth helpers
41	        User currentUser = (User) session.getAttribute("currentUser");
42	        if (currentUser.isMustChangePassword()) {
43	            boolean isPasswordChange = path.matches("/api/users/\\d+/password");
44	            boolean isAllowed = PASSWORD_CHANGE_ALLOWED.contains(path) || isPasswordChange;
45	            if (!isAllowed) {
46	                response.setStatus(HttpServletResponse.SC_FORBIDDEN);
47	                response.setContentType("application/json");
48	                response.setCharacterEncoding("UTF-8");
49	                objectMapper.writeValue(response.getWriter(),
50	                        ApiResult.error(403, "Password change required before accessing other resources"));
51	                return false;
52	            }
53	        }
54	
55	        return true;
56	    }
57	}
