10	import org.springframework.context.annotation.ComponentScan;
11	import org.springframework.context.annotation.Configuration;
12	import org.springframework.http.converter.HttpMessageConverter;
13	import org.springframework.http.converter.json.MappingJackson2HttpMessageConverter;
14	import org.springframework.web.multipart.support.StandardServletMultipartResolver;
15	import org.springframework.web.servlet.config.annotation.*;
16	import org.springframework.web.servlet.view.InternalResourceViewResolver;
17	
18	import java.text.SimpleDateFormat;
19	import java.util.List;
20	
21	@Configuration
22	@EnableWebMvc
23	@ComponentScan("com.dispatchops.web")
24	public class WebMvcConfig implements WebMvcConfigurer {
25	
26	    @Autowired
27	    private AuthInterceptor authInterceptor;
28	
29	    @Autowired
30	    private RoleInterceptor roleInterceptor;
31	
32	    @Autowired
33	    private com.dispatchops.web.interceptor.CsrfInterceptor csrfInterceptor;
34	
35	    @Override
36	    public void addInterceptors(InterceptorRegistry registry) {
37	        registry.addInterceptor(authInterceptor)
38	                .addPathPatterns("/api/**")
39	                .excludePathPatterns("/api/auth/login", "/api/health", "/api/payments/callback", "/api/credibility/ratings/customer", "/api/credibility/appeals/customer");
40	
41	        registry.addInterceptor(csrfInterceptor)
42	                .addPathPatterns("/api/**")
43	                .excludePathPatterns("/api/auth/login", "/api/health", "/api/payments/callback", "/api/credibility/ratings/customer", "/api/credibility/appeals/customer");
44	
45	        registry.addInterceptor(roleInterceptor)
46	                .addPathPatterns("/api/**")
47	                .excludePathPatterns("/api/auth/login", "/api/health", "/api/payments/callback", "/api/credibility/ratings/customer", "/api/credibility/appeals/customer");
48	    }
49	
50	    @Override
51	    public void configureMessageConverters(List<HttpMessageConverter<?>> converters) {
52	        MappingJackson2HttpMessageConverter converter = new MappingJackson2HttpMessageConverter();
53	        ObjectMapper objectMapper = new ObjectMapper();
54	        objectMapper.registerModule(new JavaTimeModule());
55	        objectMapper.setDateFormat(new SimpleDateFormat("yyyy-MM-dd'T'HH:mm:ss.SSSXXX"));
56	        objectMapper.disable(SerializationFeature.WRITE_DATES_AS_TIMESTAMPS);
57	        converter.setObjectMapper(objectMapper);
58	        converters.add(converter);
59	    }
60	
61	    @Bean
62	    public InternalResourceViewResolver viewResolver() {
63	        InternalResourceViewResolver resolver = new InternalResourceViewResolver();
64	        resolver.setPrefix("/WEB-INF/jsp/");
65	        resolver.setSuffix(".jsp");
66	        return resolver;
67	    }
68	
69	    @Override
70	    public void addResourceHandlers(ResourceHandlerRegistry registry) {
71	        registry.addResourceHandler("/static/**")
72	                .addResourceLocations("/static/");
73	    }
74	
75	    @Bean
76	    public StandardServletMultipartResolver multipartResolver() {
77	        return new StandardServletMultipartResolver();
78	    }
79	
80	    @Override
81	    public void configureAsyncSupport(AsyncSupportConfigurer configurer) {
82	        configurer.setDefaultTimeout(30000);
83	    }
84	}
